function solve(edges, online, k) {
    const n = online.length;
    const graph = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push({ node: v, cost });
    }

    // Use a priority queue to perform a modified Dijkstra's algorithm
    // We want to maximize the minimum edge cost on the path
    const pq = new PriorityQueue((a, b) => b.cost - a.cost);
    pq.enqueue({ node: 0, totalCost: 0, minEdge: Infinity });

    // Track the maximum minimum edge cost found
    let maxMinEdge = -1;

    while (!pq.isEmpty()) {
        const { node, totalCost, minEdge } = pq.dequeue();

        // If we reach the destination node
        if (node === n - 1) {
            maxMinEdge = Math.max(maxMinEdge, minEdge);
            continue;
        }

        // If the total cost exceeds k, skip this path
        if (totalCost > k) {
            continue;
        }

        // Explore neighbors
        if (graph.has(node)) {
            for (const { node: neighbor, cost } of graph.get(node)) {
                // Check if the neighbor is online
                if (online[neighbor]) {
                    const newTotalCost = totalCost + cost;
                    const newMinEdge = Math.min(minEdge, cost);

                    // Only add to the queue if the new total cost is within k
                    if (newTotalCost <= k) {
                        pq.enqueue({ node: neighbor, totalCost: newTotalCost, minEdge: newMinEdge });
                    }
                }
            }
        }
    }

    return maxMinEdge === -1 ? -1 : maxMinEdge;
}

class PriorityQueue {
    constructor(comparator) {
        this.comparator = comparator;
        this.heap = [];
    }

    enqueue(item) {
        this.heap.push(item);
        this.heapifyUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.heap.length === 0) return null;
        const item = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.heapifyDown(0);
        return item;
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    heapifyUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.comparator(this.heap[index], this.heap[parentIndex]) >= 0) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    heapifyDown(index) {
        const leftChild = 2 * index + 1;
        const rightChild = 2 * index + 2;
        let smallest = index;

        if (leftChild < this.heap.length && this.comparator(this.heap[leftChild], this.heap[smallest]) < 0) {
            smallest = leftChild;
        }

        if (rightChild < this.heap.length && this.comparator(this.heap[rightChild], this.heap[smallest]) < 0) {
            smallest = rightChild;
        }

        if (smallest !== index) {
            [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
            this.heapifyDown(smallest);
        }
    }
}

