use std::collections::HashMap;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    let mut graph = HashMap::new();

    // Build the graph
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost = edge[2];
        if !graph.contains_key(u) {
            graph.insert(u, Vec::new());
        }
        graph.get_mut(u).unwrap().push((v, cost));
    }

    // Use a priority queue to perform a modified Dijkstra's algorithm
    // We want to maximize the minimum edge cost on the path
    let mut pq = PriorityQueue::new(|a, b| b.1.cmp(&a.1) == Ordering::Equal || b.1 > a.1);
    pq.push((0, 0, i64::MAX));

    // Track the maximum minimum edge cost found
    let mut max_min_edge = -1;

    while let Some((node, total_cost, min_edge)) = pq.pop() {
        // If we reach the destination node
        if node == n - 1 {
            max_min_edge = std::cmp::max(max_min_edge, min_edge);
            continue;
        }

        // If the total cost exceeds k, skip this path
        if total_cost > k {
            continue;
        }

        // Explore neighbors
        if let Some(neighbors) = graph.get(&node) {
            for &(neighbor, cost) in neighbors {
                // Check if the neighbor is online
                if online[neighbor] {
                    let new_total_cost = total_cost + cost;
                    let new_min_edge = std::cmp::min(min_edge, cost);

                    // Only add to the queue if the new total cost is within k
                    if new_total_cost <= k {
                        pq.push((neighbor, new_total_cost, new_min_edge));
                    }
                }
            }
        }
    }

    if max_min_edge == -1 {
        -1
    } else {
        max_min_edge
    }
}

struct PriorityQueue<T> {
    heap: Vec<T>,
    comparator: Box<dyn Fn(&T, &T) -> Ordering>,
}

impl<T> PriorityQueue<T> {
    fn new(comparator: impl Fn(&T, &T) -> Ordering + 'static) -> Self {
        PriorityQueue {
            heap: Vec::new(),
            comparator: Box::new(comparator),
        }
    }

    fn push(&mut self, item: T) {
        self.heap.push(item);
        self.heapify_up(self.heap.len() - 1);
    }

    fn pop(&mut self) -> Option<T> {
        if self.heap.is_empty() {
            return None;
        }
        let item = self.heap[0].clone();
        self.heap[0] = self.heap.last().unwrap().clone();
        self.heap.pop();
        self.heapify_down(0);
        Some(item)
    }

    fn heapify_up(&mut self, index: usize) {
        while index > 0 {
            let parent_index = (index - 1) / 2;
            if (self.comparator(&self.heap[index], &self.heap[parent_index])) >= Ordering::Equal {
                self.heap.swap(index, parent_index);
                index = parent_index;
            } else {
                break;
            }
        }
    }

    fn heapify_down(&mut self, index: usize) {
        let left_child = 2 * index + 1;
        let right_child = 2 * index + 2;
        let mut smallest = index;

        if left_child < self.heap.len() && (self.comparator(&self.heap[left_child], &self.heap[smallest])) < Ordering::Equal {
            smallest = left_child;
        }

        if right_child < self.heap.len() && (self.comparator(&self.heap[right_child], &self.heap[smallest])) < Ordering::Equal {
            smallest = right_child;
        }

        if smallest != index {
            self.heap.swap(index, smallest);
            self.heapify_down(smallest);
        }
    }
}
