        let cost = edge[2];
        if !graph.contains_key(u) {
            graph.insert(u, Vec::new());
        }
        graph.get_mut(u).unwrap().push((v, cost));
    }

    let mut pq = PriorityQueue::new(|a, b| {
        if a.min_edge > b.min_edge {
            Ordering::Less
        } else if a.min_edge < b.min_edge {
            Ordering::Greater
        } else {
            Ordering::Equal
        }
    });

    pq.enqueue((0, 0, i64::MAX));

    let mut max_min_edge = -1;

    while let Some((node, total_cost, min_edge)) = pq.dequeue() {
        if node == n - 1 {
            max_min_edge = std::cmp::max(max_min_edge, min_edge);
            continue;
        }

